#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, x1, y1, x2, y2;
        scanf("%lld %lld %lld %lld %lld", &N, &x1, &y1, &x2, &y2);
        if (N == 1) {
            if (x1 == x2) printf("Draw\n");
            else printf("Miron\n");
        } else if (N == 2) {
            if (x1 == x2 && y1 == y2) printf("Draw\n");
            else printf("Miron\n");
        } else if (N == 3) {
            if (x1 == x2 && y1 == y2) printf("Draw\n");
            else if (x1 == x2) printf("Slava\n");
            else printf("Miron\n");
        } else {
            if (x1 == x2) printf("Slava\n");
            else printf("Miron\n");
        }
    }
    return 0;
}

